#include <bits/stdc++.h>
using namespace std;
int main()
{
    int n;
    double a,b,c,a1,b1,c1,a2=0,b2=0,c2=0;
    cin>>n>>a>>a1>>b>>b1>>c>>c1;
    a2=ceil(n/a)*a1;
    b2=ceil(n/b)*b1;
    c2=ceil(n/c)*c1;
    if((a2<=b2)&&(a2<=c2))
    {
        cout<<a2;
    }
    else if((b2<=a2)&&(b2<=c2))
    {
        cout<<b2;
    }
    else
    {
        cout<<c2;
    }
    return 0;
}
